text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트가 통과하는 경우 금요일 15:00 KST로 정함.",
        "certainty": "확정"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토함.",
        "certainty": "확정"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일에 릴리스하자는 제안",
        "result": "거절됨",
        "reason": "스모크 테스트 통과가 선행되어야 한다는 이의가 있었음."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경하자는 제안",
        "result": "거절됨",
        "reason": "우선은 패키지 설정 확인이 맞고, 계약 자체가 잘못된 경우에만 스크립트를 검토하기로 함."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스를 내부 스트레치 목표로 삼자는 언급",
        "status": "내부 목표로만 언급되었고 최종 일정으로 채택되지 않음"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "status": "가능하면 목요일까지 검토하자는 의견이 있었지만 담당자가 정해지지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있음"
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "명시됨"
    }
  ],
  "followup_note": {
    "next_checks": [
      "스모크 테스트 통과 여부를 먼저 확인한다.",
      "tarball 경로가 올바른지 확인한다.",
      "README 설치 단계의 최신성을 점검하되 담당자와 시점은 별도 확인이 필요하다.",
      "최종 릴리스 승인 권한자와 릴리스 노트에 내부 목표를 넣을지 여부를 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너명",
      "예산 정보",
      "보안 사고 여부",
      "프로덕션 장애 여부",
      "법무 승인 필요 여부",
      "할당되지 않은 담당자",
      "명시되지 않은 추가 마감 시각"
    ]
  },
  "non_invention_rules": [
    "명시되지 않은 고객명은 만들지 않는다.",
    "명시되지 않은 예산, 보안, 장애, 법무 사실은 추가하지 않는다.",
    "담당자가 정해지지 않은 항목에 소유자를 임의 배정하지 않는다.",
    "마감 시간이 없으면 구체 시각을 추정하지 않고 '미정'으로 둔다.",
    "합의되지 않은 제안은 확정 결정으로 쓰지 않는다.",
    "내부 스트레치 목표를 최종 일정으로 승격하지 않는다."
  ]
}
